sequence.script:
var payload = mc.getPayloadJSON();

var policyPeriodMap = {
    "3 Months": 3,
    "6 Months": 6,
    "1 Year": 12,
    "2 Years": 24
};

var periodMonths = policyPeriodMap[payload.policyPeriod] || 12;

function calculateEndDate(startDate, months) {
    var d = new Date(startDate);
    d.setMonth(d.getMonth() + months);
    return d.toISOString().split("T")[0];
}

function baseAnnualPremium(vehicle) {
    return (vehicle.vehicleValue * 0.02)
        + (vehicle.vehicleModelYear < 2020 ? 2000 : 0)
        + (vehicle.vehicleTypeCode === "SEDAN" ? 1500 : 2500);
}

function proratedPremium(annual, months) {
    return (annual / 12) * months;
}

var vehiclePremiums = [];
var totalPremium = 0;

(payload.insurableObjects || [])
    .filter(function(io) {
        return io.insurableObjectTypeCode === "VEHICLE";
    })
    .forEach(function(item, idx) {

        var base = baseAnnualPremium(item.vehicle);
        var calc = proratedPremium(base, periodMonths);

        vehiclePremiums.push({
            vehicleIndex: idx + 1,
            baseAnnualPremium: base,
            calculatedPremium: calc
        });

        totalPremium += calc;
    });

var premiumResult = {
    termStartDate: payload.termStartDate,
    termEndDate: calculateEndDate(payload.termStartDate, periodMonths),
    policyPeriodMonths: periodMonths,
    vehiclePremiums: vehiclePremiums,
    totalPremium: totalPremium
};

// Store property
mc.setProperty("premiumResult", JSON.stringify(premiumResult));


// =====================================================
//  ADD PRICING OBJECT (Equivalent to Mule DW)
// =====================================================

// Get stored property
var storedPremium = JSON.parse(mc.getProperty("premiumResult"));

// Remove documents and pricing fields
delete payload.documents;
delete payload.pricing;

// Add new pricing object
payload.pricing = {
    totalPremium: storedPremium.totalPremium,
    grossFees: 500,
    amounts: [
        {
            amountTypeCode: "PREMIUM",
            amountValue: storedPremium.totalPremium,
            currencyCode: "USD"
        },
        {
            amountTypeCode: "FEE",
            amountValue: 500,
            currencyCode: "USD"
        }
    ]
};

// Set updated payload back
mc.setPayloadJSON(payload);

// Get incoming payload
var payload = mc.getPayloadJSON();

// Get calculated premium property
var premiumProp = mc.getProperty("premiumResult");   // or "calculatedPremium"
var calculatedPremium = JSON.parse(premiumProp);

// Build response object
var response = {
    update: {
        documents: [{
            binaryData: payload.data,
            documentTypeCode: payload.fileName,
            displayName: payload.documentId,
            type: "PDF",
            generatedDate: new Date().toISOString().split("T")[0]
        }],
        pricing: {
            totalPremium: calculatedPremium.totalPremium,
            grossFees: 500,
            amounts: [
                {
                    amountTypeCode: "PREMIUM",
                    amountValue: calculatedPremium.totalPremium,
                    currencyCode: "USD"
                },
                {
                    amountTypeCode: "FEE",
                    amountValue: 500,
                    currencyCode: "USD"
                }
            ]
        }
    }
};

// Set final payload
mc.setPayloadJSON(response);
